const now = new Date();
const cutoff = new Date(now.getTime() + 48 * 60 * 60 * 1000);

const urgent = $input.all().filter(item => {
  const due = item.json.properties['Due Date']?.date?.start;
  if (!due) return false;
  const dueDate = new Date(due);
  return dueDate <= cutoff;
});

return urgent.map(item => {
  const props = item.json.properties;
  return {
    json: {
      description: props['Description']?.title?.[0]?.plain_text,
      assignedTo: props['Assigned To']?.select?.name,
      episode: props['Episode (text)']?.rich_text?.[0]?.plain_text,
      dueDate: props['Due Date']?.date?.start,
      show: props['Show']?.select?.name,
      pageUrl: `https://www.notion.so/${item.json.id.replace(/-/g, '')}`
    }
  };
});

const items = $input.all();
const byPerson = {};
items.forEach(item => {
  const person = item.json.assignedTo || 'Unassigned';
  if (!byPerson[person]) byPerson[person] = [];
  byPerson[person].push(`• ${item.json.description} (${item.json.episode} ${item.json.show}) — Due: ${item.json.dueDate}`);
});

const lines = Object.entries(byPerson).map(([person, tasks]) =>
  `${person}:\n${tasks.join('\n')}`
).join('\n\n');

return [{ json: { message: `GSR Graphics Due Soon:\n\n${lines}`, count: items.length } }];
